import clsx from 'clsx';
import { useIntl } from 'react-intl';

import Spacings from '@dynatrace/strato-design-tokens/spacings';

import { rangeHeaderText } from './intl-messages.js';
import type { Formatter } from '../../../../../types/formatter.js';
import { HeaderChipAtom } from '../../../../tooltip-atoms/components/HeaderChipAtom/HeaderChipAtom.js';
import { TooltipText } from '../../../section-components/atoms/TooltipText.js';
import { TooltipItem } from '../../../section-components/TooltipItem/TooltipItem.js';

/** @internal */
export interface RangeHeaderProps {
  from: number;
  to: number;
  formatter: Formatter;
  absoluteRange?: boolean;
  className?: string;
}

/**
 * @internal
 */
export const RangeHeader = ({
  from,
  to,
  formatter,
  absoluteRange,
  className,
}: RangeHeaderProps) => {
  const intl = useIntl();

  const text = intl.formatMessage(rangeHeaderText);
  const rangeValue = absoluteRange ? Math.abs(to - from) : to - from;

  return (
    <TooltipItem>
      <HeaderChipAtom
        style={{ marginRight: Spacings.Size4 }}
        className={clsx(className)}
      >
        {formatter(rangeValue)}
      </HeaderChipAtom>
      <TooltipText variant="secondary">
        {`${formatter(from)} ${text} ${formatter(to)}`}
      </TooltipText>
    </TooltipItem>
  );
};
